UPDATE "ec_posts" SET "source_seo" = '{"title":"Arama Yılı Vizesi: Türkiye''de Mezuniyet Sonrası İmkanlar","description":"Türkiye’de mezuniyet sonrası arama yılı vizesi ile kariyer fırsatlarını yakalayın. Başvuru koşulları ve yasal hakları hemen öğrenin!","robots":"follow, index, max-snippet:-1, max-video-preview:-1, max-image-preview:large","ogTitle":"Arama Yılı Vizesi: Türkiye''de Mezuniyet Sonrası İmkanlar","ogDescription":"Türkiye’de mezuniyet sonrası arama yılı vizesi ile kariyer fırsatlarını yakalayın. Başvuru koşulları ve yasal hakları hemen öğrenin!","ogImage":null,"twitterCard":"summary_large_image","twitterTitle":"Arama Yılı Vizesi: Türkiye''de Mezuniyet Sonrası İmkanlar","twitterDescription":"Türkiye’de mezuniyet sonrası arama yılı vizesi ile kariyer fırsatlarını yakalayın. Başvuru koşulları ve yasal hakları hemen öğrenin!","canonicalPath":"/arama-yili-vizesi/","hreflang":[{"hreflang":"tr","href":"/arama-yili-vizesi/"},{"hreflang":"en","href":"/en/post-graduation-visa-opportunities-in-turkey/"}],"jsonLd":[{"@context":"https://schema.org","@graph":[{"@type":["Organization","Person"],"@id":"https://roadtostudy.com/#person","name":"Road to Study - Turkey University Guide for Students","url":"https://roadtostudy.com","logo":{"@type":"ImageObject","@id":"https://roadtostudy.com/#logo","url":"https://roadtostudy.com/wp-content/uploads/2025/02/Kare-Logo-e1740739634958.png","contentUrl":"https://roadtostudy.com/wp-content/uploads/2025/02/Kare-Logo-e1740739634958.png","caption":"Road to Study - Turkey University Guide for Students","inLanguage":"tr","width":"450","height":"445"},"image":{"@id":"https://roadtostudy.com/#logo"}},{"@type":"WebSite","@id":"https://roadtostudy.com/#website","url":"https://roadtostudy.com","name":"Road to Study - Turkey University Guide for Students","alternateName":"Road to Study in Turkey","publisher":{"@id":"https://roadtostudy.com/#person"},"inLanguage":"tr"},{"@type":"WebPage","@id":"https://roadtostudy.com/arama-yili-vizesi/#webpa